/**
 * Verifica se a pasta ~/Documents/Nexxt_Mogrts estأ­ vazia.
 * Se sim, baixa os MOGRTs da nuvem e extrai lأ­.
 */
async function instalarMogrtsSeNecessario() {
    const fs = require('fs');
    const path = require('path');
    const os = require('os');
    const { exec } = require('child_process');

    const destDir = path.join(os.homedir(), 'Documents', 'Nexxt_Mogrts');
    if (!fs.existsSync(destDir)) fs.mkdirSync(destDir, { recursive: true });

    // Se jأ­ existem MOGRTs, nأ؛o precisa baixar novamente
    const existing = fs.readdirSync(destDir).filter(f => f.endsWith('.mogrt'));
    if (existing.length > 0) return;

    const listContainer = document.getElementById('mogrt-list');

    // ===========================================================
    // Helpers de UI
    // ===========================================================
    function setUI(icon, title, sub, spin) {
        if (!listContainer) return;
        listContainer.style.cssText = 'display:flex;flex-direction:column;align-items:center;justify-content:center;';
        listContainer.innerHTML = `
            <div style="padding:30px;text-align:center;color:var(--text-secondary);">
                <div style="font-size:32px;margin-bottom:12px;${spin ? 'animation:spin 1.5s linear infinite;' : ''}">${icon}</div>
                <div style="font-weight:600;font-size:14px;color:white;">${title}</div>
                ${sub ? `<div style="font-size:11px;margin-top:6px;opacity:0.7;">${sub}</div>` : ''}
            </div>
            <style>@keyframes spin{100%{transform:rotate(360deg)}}</style>`;
    }

    function setProgressUI(downloaded, total) {
        if (!listContainer) return;
        const pct = total > 0 ? Math.round((downloaded / total) * 100) : 0;
        const mb = (downloaded / 1048576).toFixed(1);
        const totalMb = total > 0 ? (total / 1048576).toFixed(0) + 'MB' : '...';
        listContainer.style.cssText = 'display:flex;flex-direction:column;align-items:center;justify-content:center;padding:20px;';
        listContainer.innerHTML = `
            <div style="width:100%;max-width:280px;text-align:center;">
                <div style="font-size:28px;margin-bottom:12px;">أ´أ‘</div>
                <div style="font-weight:600;font-size:13px;color:white;margin-bottom:8px;">Baixando pacotes de legendas...</div>
                <div style="background:rgba(255,255,255,0.08);border-radius:6px;height:6px;overflow:hidden;margin-bottom:6px;">
                    <div style="background:var(--accent-primary,#6366f1);height:100%;width:${pct}%;transition:width 0.3s;border-radius:6px;"></div>
                </div>
                <div style="font-size:11px;opacity:0.6;">${mb}MB / ${totalMb} (${pct}%)</div>
                <div style="font-size:10px;margin-top:4px;opacity:0.4;">Isso acontece apenas na primeira execuآ؛أ؛o.</div>
            </div>`;
    }

    function setErrorUI(isRarManual) {
        if (!listContainer) return;
        if (isRarManual) {
            listContainer.style.cssText = 'display:flex;flex-direction:column;align-items:center;justify-content:center;padding:20px;';
            listContainer.innerHTML = `
                <div style="max-width:280px;text-align:center;">
                    <div style="font-size:28px;margin-bottom:10px;">أ´أ¼</div>
                    <div style="font-weight:600;font-size:13px;color:white;margin-bottom:6px;">Instalar Templates Manualmente</div>
                    <div style="font-size:11px;color:rgba(255,255,255,0.5);margin-bottom:14px;">
                        Baixe o arquivo e extraia os MOGRTs para:<br>
                        <span style="color:var(--accent-primary,#6366f1);font-size:10px;">Documentos/Nexxt_Mogrts</span>
                    </div>
                    <button onclick="(window.csInterface||csInterface).openURLInDefaultBrowser('https://github.com/editnexxt-code/Releases/releases/latest')"
                        style="padding:9px 14px;background:var(--accent-primary,#6366f1);border:none;border-radius:8px;color:white;font-size:12px;font-weight:600;cursor:pointer;width:100%;margin-bottom:8px;">
                         Baixar Templates Manualmente
                    </button>
                    <button onclick="instalarMogrtsSeNecessario()"
                        style="padding:8px 14px;background:rgba(255,255,255,0.05);border:1px solid rgba(255,255,255,0.1);border-radius:8px;color:rgba(255,255,255,0.6);font-size:11px;cursor:pointer;width:100%;">
                         Tentar Novamente
                    </button>
                </div>`;
        } else {
            listContainer.style.cssText = 'display:flex;flex-direction:column;align-items:center;justify-content:center;padding:20px;';
            listContainer.innerHTML = `
                <div style="text-align:center;">
                    <div style="font-size:24px;margin-bottom:8px;">آ´آ©أ…</div>
                    <div style="font-size:12px;color:#ef4444;margin-bottom:12px;">Falha no download dos templates.</div>
                    <button onclick="instalarMogrtsSeNecessario()"
                        style="padding:8px 16px;background:var(--accent-primary,#6366f1);border:none;border-radius:8px;color:white;font-size:12px;font-weight:600;cursor:pointer;">
                         Tentar Novamente
                    </button>
                </div>`;
        }
    }

    try {
        // ===========================================================
        // PASSO 1: Descobre URL do arquivo de MOGRTs via GitHub API
        // (sempre busca a release mais recente nأ؛o hardcoded)
        // ===========================================================
        setUI('', 'Verificando pacotes disponآ،veis...', null, true);

        let downloadUrl = null;
        let fileName = null;

        try {
            const apiResp = await fetch('https://api.github.com/repos/editnexxt-code/Releases/releases/latest');
            const releaseData = await apiResp.json();
            // Procura qualquer asset que comece com 'Nexxt_Mogrts' (.zip ou .rar)
            const asset = (releaseData.assets || []).find(a => /^Nexxt_Mogrts\.(zip|rar)$/i.test(a.name));
            if (asset) {
                downloadUrl = asset.browser_download_url;
                fileName = asset.name;
            }
        } catch (apiErr) {
            console.warn('[instalarMogrts] GitHub API falhou, usando URL de fallback:', apiErr);
        }

        // Fallback caso a API falhe ou nأ؛o encontre o asset
        // IMPORTANTE: sempre usar .zip funciona em qualquer OS sem dependآ¬ncia externa
        if (!downloadUrl) {
            downloadUrl = 'https://github.com/editnexxt-code/Releases/releases/download/v1.2.0/Nexxt_Mogrts.zip';
            fileName = 'Nexxt_Mogrts.zip';
        }

        // Forآ؛a tratamento como ZIP se a extensأ؛o for .rar mas temos .zip disponآ،vel
        // (o GitHub sempre terأ­ .zip a partir de agora)
        const isZip = !fileName.toLowerCase().endsWith('.rar');
        const tempExt = isZip ? '.zip' : '.rar';
        const tempFilePath = path.join(os.tmpdir(), 'Nexxt_Mogrts_' + Date.now() + tempExt);

        // ===========================================================
        // PASSO 2: Download com barra de progresso em bytes reais
        // Segue redirects do GitHub أ† AWS S3 automaticamente
        // ===========================================================
        await new Promise((resolve, reject) => {
            const https = require('https');
            function downloadFile(url, dest) {
                https.get(url, (res) => {
                    if (res.statusCode === 301 || res.statusCode === 302) {
                        downloadFile(res.headers.location, dest);
                        return;
                    }
                    if (res.statusCode !== 200) {
                        return reject(new Error('Erro HTTP ' + res.statusCode + ' ao baixar os templates. Verifique sua conexأ؛o.'));
                    }
                    // Validaآ؛أ؛o: arquivo muito pequeno = provavelmente pأ­gina de erro HTML
                    const total = parseInt(res.headers['content-length'] || '0', 10);
                    if (total > 0 && total < 1000000) {
                        res.destroy();
                        return reject(new Error('Arquivo invأ­lido recebido (muito pequeno). O arquivo pode nأ؛o existir no servidor.'));
                    }
                    let downloaded = 0;
                    const file = fs.createWriteStream(dest);
                    res.on('data', chunk => {
                        downloaded += chunk.length;
                        setProgressUI(downloaded, total);
                    });
                    res.pipe(file);
                    file.on('finish', () => { file.close(); resolve(); });
                }).on('error', err => {
                    if (fs.existsSync(dest)) try { fs.unlinkSync(dest); } catch (e) { }
                    reject(err);
                });
            }
            downloadFile(downloadUrl, tempFilePath);
        });

        // ===========================================================
        // PASSO 3: Extraآ؛أ؛o via adm-zip (.zip nativo, sem dependآ¬ncia)
        // ===========================================================
        setUI('أ´آھ', 'Extraindo pacotes...', null, false);
        await new Promise(r => setTimeout(r, 300));

        if (isZip) {
            // Valida magic bytes antes de extrair (zip comeأ§a com PK = 0x50 0x4B)
            const header = Buffer.alloc(4);
            const fd = fs.openSync(tempFilePath, 'r');
            fs.readSync(fd, header, 0, 4, 0);
            fs.closeSync(fd);
            if (header[0] !== 0x50 || header[1] !== 0x4B) {
                try { fs.unlinkSync(tempFilePath); } catch (e) { }
                throw new Error('Arquivo corrompido ou invأ،lido recebido. Tente novamente.');
            }
            const AdmZip = safeRequire('adm-zip');
            if (AdmZip) {
                const zip = new AdmZip(tempFilePath);
                zip.extractAllTo(destDir, true);
            } else if (process.platform === 'darwin' || process.platform === 'linux') {
                // Fallback macOS/Linux: usa unzip nativo do sistema
                await new Promise((res, rej) => exec(`unzip -o "${tempFilePath}" -d "${destDir}"`, err => err ? rej(new Error('Falha ao extrair ZIP com unzip: ' + err.message)) : res()));
            } else {
                // Fallback Windows: usa tar nativo do Win10+
                await new Promise((res, rej) => {
                    const { execFile } = require('child_process');
                    execFile('C:\\Windows\\System32\\tar.exe', ['-xf', tempFilePath, '-C', destDir], err => err ? rej(new Error('Falha ao extrair ZIP: ' + err.message)) : res());
                });
            }
        } else {
            // Fallback .rar (caso antigo)
            let extracted = false;
            if (process.platform === 'darwin') {
                // macOS: tenta unar (brew install unar) ou unzip
                const macCmds = [
                    `unar -o "${destDir}" "${tempFilePath}"`,
                    `unzip -o "${tempFilePath}" -d "${destDir}"`
                ];
                for (const cmd of macCmds) {
                    try {
                        await new Promise((res, rej) => exec(cmd, err => err ? rej(err) : res()));
                        extracted = true;
                        break;
                    } catch (e) { /* tenta o prأ³ximo */ }
                }
            } else {
                const rarCmds = [
                    `"C:\\Program Files\\7-Zip\\7z.exe" x "${tempFilePath}" -o"${destDir}" -y`,
                    `"C:\\Program Files (x86)\\7-Zip\\7z.exe" x "${tempFilePath}" -o"${destDir}" -y`,
                    `"C:\\Program Files\\WinRAR\\WinRAR.exe" x -y "${tempFilePath}" "${destDir}\\"`
                ];
                for (const cmd of rarCmds) {
                    try {
                        await new Promise((res, rej) => exec(cmd, err => err ? rej(err) : res()));
                        extracted = true;
                        break;
                    } catch (e) { /* tenta o prأ³ximo */ }
                }
            }
            if (!extracted) {
                try { fs.unlinkSync(tempFilePath); } catch (e) { }
                setErrorUI(true);
                return;
            }
        }

        try { fs.unlinkSync(tempFilePath); } catch (e) { }

        notify('أ”آ£أ  Templates instalados com sucesso!', 'success');
        renderizarListaMogrts();

    } catch (e) {
        console.error('[instalarMogrtsSeNecessario]', e);
        notify('Erro ao baixar os templates: ' + e.message, 'error');
        setErrorUI(false);
    }
}

function listarMogrtsDisponiveis() {
    const fs = require('fs');
    const path = require('path');
    const os = require('os');
    const pasta = path.join(os.homedir(), 'Documents', 'Nexxt_Mogrts');
    if (!fs.existsSync(pasta)) fs.mkdirSync(pasta, { recursive: true });

    return fs.readdirSync(pasta)
        .filter(f => f.endsWith('.mogrt'))
        .map(f => {
            const baseStr = f.replace('.mogrt', '');
            const basePath = path.join(pasta, baseStr);
            let thumbPath = null;

            if (fs.existsSync(basePath + '.png')) thumbPath = basePath + '.png';
            else if (fs.existsSync(basePath + '.jpg')) thumbPath = basePath + '.jpg';
            else if (fs.existsSync(basePath + '.jpeg')) thumbPath = basePath + '.jpeg';

            return {
                nome: baseStr,
                caminho: path.join(pasta, f).replace(/\\/g, '/'),
                thumb: thumbPath ? thumbPath.replace(/\\/g, '/') : null
            };
        });
}

function renderizarListaMogrts(skipAsync = false) {
    const container = document.getElementById('mogrt-list');
    if (!container) return;

    const mogrts = listarMogrtsDisponiveis();

    if (mogrts.length === 0) {
        container.innerHTML = "<div style='grid-column:1/-1;text-align:center;padding:20px;font-size:12px;color:gray;'>Nenhum MOGRT encontrado na pasta:<br>Documentos/Nexxt_Mogrts</div>";
        return;
    }

    container.innerHTML = "";

    // ========================================================================
    // (Dropzone removida a pedido do usuأ­rio)
    // ========================================================================

    let encontrouSelecao = false;

    mogrts.forEach((m, i) => {
        const div = document.createElement('div');

        let shouldBeActive = false;
        if (selectedMogrtPath) {
            if (m.caminho === selectedMogrtPath) shouldBeActive = true;
        } else if (i === 0) {
            shouldBeActive = true;
        }

        if (shouldBeActive) {
            div.className = "mogrt-item active";
            selectedMogrtPath = m.caminho;
            encontrouSelecao = true;
        } else {
            div.className = "mogrt-item";
        }

        let thumbHTML = m.thumb
            ? `<img src="file:///${m.thumb}?t=${Date.now()}" alt="${m.nome}">`
            : `<div style="font-size: 24px; color: rgba(255,255,255,0.1); font-weight: bold; font-family: serif;">M</div>`;

        div.innerHTML = `
            <div class="mogrt-thumb-wrapper">
                ${thumbHTML}
                <div class="mogrt-active-overlay"></div>
                <div class="mogrt-checkbox"></div>
            </div>
            <div class="mogrt-info" title="${m.nome}">${m.nome}</div>
        `;

        div.onclick = () => {
            document.querySelectorAll('.mogrt-item').forEach(e => {
                e.classList.remove('active');
            });
            div.classList.add('active');
            selectedMogrtPath = m.caminho;
        };

        container.appendChild(div);
    });

    if (!encontrouSelecao && mogrts.length > 0) {
        selectedMogrtPath = mogrts[0].caminho;
    }

    if (!skipAsync) {
        setTimeout(() => extrairMogrtThumbnailsAsync(mogrts), 500);
    }
}

function extrairMogrtThumbnailsAsync(mogrts) {
    const missingThumbs = mogrts.filter(m => !m.thumb);
    if (missingThumbs.length === 0) return;

    const fs = require('fs');
    const path = require('path');
    const os = require('os');
    const { exec } = require('child_process');

    const container = document.getElementById('mogrt-list');
    if (container) {
        container.insertAdjacentHTML('afterbegin', '<div id="mogrt-loading-thumb" style="grid-column: 1/-1; text-align:center; font-size:10px; color:var(--accent-primary); padding: 5px;">Extraindo thumbnails originais...</div>');
    }

    const removeLoader = () => {
        const loader = document.getElementById('mogrt-loading-thumb');
        if (loader) loader.remove();
    };

    // ================================================================
    // SOLUأ§أ¢O 4: CROSS-PLATFORM THUMBNAIL EXTRACTION
    // ================================================================
    // Estratآ®gia em cascata:
    // 1. Tenta adm-zip (Node.js nativo, funciona em qualquer OS)
    // 2. Fallback PowerShell para Windows
    // 3. Fallback 'unzip' para macOS/Linux
    // ================================================================

    // ESTRATأ«GIA 1: adm-zip (se o mdulo estiver instalado)
    let usedAdmZip = false;
    try {
        const AdmZip = require('adm-zip'); // instalأ­vel via: npm install adm-zip
        missingThumbs.forEach(m => {
            try {
                const basePath = m.caminho.substring(0, m.caminho.lastIndexOf('.mogrt'));
                const zip = new AdmZip(m.caminho);
                const entries = zip.getEntries();
                // Prefere 'project_thumbnail' se existir
                const thumb = entries
                    .filter(e => /\.(png|jpg|jpeg)$/i.test(e.entryName))
                    .sort((a, b) => (a.entryName.includes('project_thumbnail') ? -1 : 1))[0];
                if (thumb) {
                    const destPath = basePath + '.png';
                    fs.writeFileSync(destPath, thumb.getData());
                }
            } catch (e) { /* arquivo corrompido, ignora */ }
        });
        usedAdmZip = true;
        removeLoader();
        renderizarListaMogrts(true);
        return;
    } catch (e) {
        // adm-zip nأ؛o disponآ،vel prossegue com fallback nativo de OS
    }

    if (!usedAdmZip) {
        const platform = os.platform(); // 'win32' | 'darwin' | 'linux'

        if (platform === 'win32') {
            // ESTRATأ«GIA 2: tar.exe nativo do Windows 10+ (Substituindo PowerShell)
            let batScript = "@echo off\n";
            missingThumbs.forEach((m, i) => {
                const basePath = m.caminho.substring(0, m.caminho.lastIndexOf('.mogrt'));
                const tmpDir = path.join(os.tmpdir(), 'nexxt_thumb_' + Date.now() + '_' + i);
                batScript += `mkdir "${tmpDir}" 2>nul\n`;
                batScript += `tar -xf "${m.caminho}" -C "${tmpDir}" "*.png" "*.jpg" 2>nul\n`;
                batScript += `for %%I in ("${tmpDir}\\*.png" "${tmpDir}\\*.jpg") do (copy /Y "%%I" "${basePath}.png" >nul & goto :done_${i})\n`;
                batScript += `:done_${i}\n`;
                batScript += `rmdir /s /q "${tmpDir}" 2>nul\n`;
            });

            const tempScript = path.join(os.tmpdir(), "extract_mogrts_" + Date.now() + ".bat");
            fs.writeFileSync(tempScript, batScript, "utf8");

            exec(`"${tempScript}"`, (err) => {
                try { fs.unlinkSync(tempScript); } catch (e) { }
                removeLoader();
                renderizarListaMogrts(true);
            });

        } else {
            // ESTRATأ«GIA 3: unzip no macOS/Linux
            const cmds = missingThumbs.map(m => {
                const basePath = m.caminho.substring(0, m.caminho.lastIndexOf('.mogrt'));
                const tmpDir = path.join(os.tmpdir(), 'nexxt_thumb_' + Date.now());
                return `mkdir -p "${tmpDir}" && unzip -o "${m.caminho}" "*.png" "*.jpg" -d "${tmpDir}" 2>/dev/null; f=$(ls "${tmpDir}"/*.png "${tmpDir}"/*.jpg 2>/dev/null | head -1); [ -n "$f" ] && cp "$f" "${basePath}.png"; rm -rf "${tmpDir}"`;
            }).join(' ; ');

            exec(cmds, () => {
                removeLoader();
                renderizarListaMogrts(true);
            });
        }
    }
}

