function initCaptionsUI() {
    // 2. Sliders: Caracteres, Duraآ؛أ؛o Mآ،nima, Gap de Frames
    const sliderChars = document.getElementById('slider-chars');
    const charCountVal = document.getElementById('char-count-val');
    if (sliderChars && charCountVal) {
        sliderChars.oninput = (e) => { charCountVal.innerText = e.target.value; };
    }

    const sliderMinDur = document.getElementById('slider-min-duration');
    const minDurVal = document.getElementById('min-dur-val');
    if (sliderMinDur && minDurVal) {
        sliderMinDur.oninput = (e) => { minDurVal.innerText = parseFloat(e.target.value).toFixed(1); };
    }

    const sliderGap = document.getElementById('slider-gap-frames');
    const gapFrameVal = document.getElementById('gap-frames-val');
    if (sliderGap && gapFrameVal) {
        sliderGap.oninput = (e) => { gapFrameVal.innerText = e.target.value; };
    }

    // 3. Botأ؛o Abrir Pasta MOGRT
    const btnOpenFolder = document.getElementById('btn-open-mogrt-folder');
    if (btnOpenFolder) {
        btnOpenFolder.onclick = () => {
            const fs = require('fs');
            const path = require('path');
            const os = require('os');
            const { exec } = require('child_process');

            const mogrtDir = path.join(os.homedir(), 'Documents', 'Nexxt_Mogrts');

            if (!fs.existsSync(mogrtDir)) {
                try { fs.mkdirSync(mogrtDir, { recursive: true }); } catch (e) { }
            }

            if (process.platform === 'darwin') {
                exec(`open "${mogrtDir}"`);
            } else {
                exec(`explorer.exe "${mogrtDir}"`);
            }
        };
    }

    // 3b. Botأ؛o Reinstalar MOGRTs (forآ؛a re-download mesmo se pasta nأ؛o estiver vazia)
    const btnReinstallMogrts = document.getElementById('btn-reinstall-mogrts');
    if (btnReinstallMogrts) {
        btnReinstallMogrts.onclick = () => {
            if (!confirm('Isso irأ­ apagar e re-baixar todos os templates MOGRT. Continuar?')) return;
            try {
                const fs = require('fs');
                const path = require('path');
                const os = require('os');
                const destDir = path.join(os.homedir(), 'Documents', 'Nexxt_Mogrts');
                if (fs.existsSync(destDir)) {
                    fs.readdirSync(destDir).forEach(f => {
                        try { fs.unlinkSync(path.join(destDir, f)); } catch (e) { }
                    });
                }
            } catch (e) { console.warn('[btn-reinstall-mogrts] Erro ao limpar pasta:', e); }
            instalarMogrtsSeNecessario();
        };
    }

    // 4. Auto-instala MOGRTs do bundle se necessأ­rio (primeiro uso)
    instalarMogrtsSeNecessario();

    // 5. Renderiza Catأ­logo de MOGRTs Local
    renderizarListaMogrts();

}

