                        // MAX_PAUSE_THRESHOLD: se o silآ¬ncio entre duas palavras
                        // for maior que esse valor, quebra o chunk IMEDIATAMENTE.
                        // A legenda desaparece durante o silآ¬ncio sem esticar.
                        // ============================================================
                        const MAX_PAUSE_THRESHOLD = 0.4; // 400ms

